fn rbtdro_onboarding_ordain_airgap_chain_impl(ctx: &mut rbtdri_Context, dir: &Path) -> rbtdre_Verdict {
    let root = ctx.project_root().to_path_buf();

    let forge_sigil = RBTDRO_VESSEL_DIR_AIRGAP_FORGE
        .rsplit('/')
